import{c as s,Q as a,j as n,m as i}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"OpenClaw — three confirmation tiers","description":"The USD-amount classifier and per-tier confirmation flow.","frontmatter":{"title":"OpenClaw — three confirmation tiers","description":"The USD-amount classifier and per-tier confirmation flow."},"headers":[],"relativePath":"openclaw/confirmation-tiers.md","filePath":"openclaw/confirmation-tiers.md","lastUpdated":1780196777000}'),t={name:"openclaw/confirmation-tiers.md"};function p(o,e,r,l,d,h){return a(),n("div",null,[...e[0]||(e[0]=[i(`<div class="warning custom-block"><p class="custom-block-title">🚧 In development — not in the Testing Guide</p><p>This surface is still being hardened and isn&#39;t part of the <a href="/guide/">Testing Guide</a>. The page below describes the intended design. To evaluate MuHaven today, use <a href="/havenbot/overview">HavenBot</a> or the <a href="/mcp/overview">MCP server</a>.</p></div><h1 id="three-confirmation-tiers" tabindex="-1">Three confirmation tiers <a class="header-anchor" href="#three-confirmation-tiers" aria-label="Permalink to &quot;Three confirmation tiers&quot;">​</a></h1><p>The OpenClaw + Telegram surface uses a <strong>three-tier classifier</strong> based on the USD amount of the proposed action. The classifier is pure, deterministic, and locked at the type level — investors cannot raise the boundaries above the hardcoded ceilings.</p><h2 id="the-classifier" tabindex="-1">The classifier <a class="header-anchor" href="#the-classifier" aria-label="Permalink to &quot;The classifier&quot;">​</a></h2><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> classifyTier</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">amountUsd6</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> bigint</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Tier</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (amountUsd6 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 200_000_000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">n</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)    </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;inline&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           // ≤ $200</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (amountUsd6 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5_000_000_000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">n</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;mini_app_otp&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     // $200 – $5K</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;passkey_deeplink&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                    // &gt; $5K</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Three brackets, two boundaries — both inclusive on the lower side:</p><table tabindex="0"><thead><tr><th>Amount (USD, 6-decimal mhUSDC)</th><th>Tier</th><th>Surface</th></tr></thead><tbody><tr><td>≤ $200</td><td><strong>Inline</strong></td><td>Telegram inline keyboard button</td></tr><tr><td>$200 – $5,000</td><td><strong>Mini-App OTP</strong></td><td>Telegram Mini App + 6-digit OTP</td></tr><tr><td>&gt; $5,000</td><td><strong>Passkey deeplink</strong></td><td>Dashboard <code>/agent/confirm</code> with WebAuthn</td></tr></tbody></table><p>The boundaries trace to <strong>Reg BI Care Obligation</strong> + <strong>FINRA IM-2017-02</strong> framing — small retail amounts (sub-$200) are presumed informed; mid-tier amounts need an additional friction step; institutional amounts (&gt;$5K) need full passkey-bound authorization.</p><h2 id="why-the-boundaries-are-hard-coded" tabindex="-1">Why the boundaries are hard-coded <a class="header-anchor" href="#why-the-boundaries-are-hard-coded" aria-label="Permalink to &quot;Why the boundaries are hard-coded&quot;">​</a></h2><p>Investors cannot raise the ceilings via <code>set_policy</code>. There is no &quot;Telegram inline up to $1000&quot; tier — the upper bound is a system invariant, not a per-user knob.</p><p>The lower bounds <em>could</em> be lowered (e.g., a user wants the Mini-App OTP for sub-$200) but the surface doesn&#39;t expose that knob today; everyone gets the same friction floor.</p><p>This is a deliberate choice that <em>prevents</em> investor self-coercion (e.g., &quot;I&#39;ll just raise my inline tier to $5K so I can act faster&quot;) at the cost of some flexibility. The flexibility lives in the <a href="/policy/tiered-autonomy">HavenBot Confirm-per-action tier</a> which can sign within a 1-hour session-key TTL without re-prompting.</p><h2 id="tier-1-—-inline-≤-200" tabindex="-1">Tier 1 — Inline (≤$200) <a class="header-anchor" href="#tier-1-—-inline-≤-200" aria-label="Permalink to &quot;Tier 1 — Inline (≤$200)&quot;">​</a></h2><p><strong>Flow:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You → /buy 50 RWA1</span></span>
<span class="line"><span>Bot → renders inline-keyboard message:</span></span>
<span class="line"><span>        ┌─────────────────────────────────┐</span></span>
<span class="line"><span>        │ Buy 50 mhUSDC of RWA1?        │</span></span>
<span class="line"><span>        │                                  │</span></span>
<span class="line"><span>        │ [✅ Confirm]   [❌ Cancel]      │</span></span>
<span class="line"><span>        └─────────────────────────────────┘</span></span>
<span class="line"><span>You → tap Confirm</span></span>
<span class="line"><span>Bot → validates tap is from linked Telegram user_id</span></span>
<span class="line"><span>Bot → POSTs /api/v1/agent/openclaw/intent/confirm-inline</span></span>
<span class="line"><span>        body: { intentId, expectedChatId, expectedUserId, serviceSecret }</span></span>
<span class="line"><span>Backend → asserts row.tier === &#39;inline&#39;</span></span>
<span class="line"><span>Backend → asserts row.chatId === expectedChatId</span></span>
<span class="line"><span>Backend → asserts row.userId === expectedUserId via telegram_links lookup</span></span>
<span class="line"><span>Backend → submits the on-chain UserOp</span></span>
<span class="line"><span>Backend → emits SSE → bot receives → bot replies &quot;✅ Settled. Tx: 0x...&quot;</span></span></code></pre></div><p><strong>Security properties:</strong></p><ul><li>Tap-to-confirm is bound to the same chat_id + user_id that owns the intent.</li><li>The endpoint refuses any intent whose tier ≠ <code>inline</code>. A bot-worker compromise cannot escalate a $500 intent into an inline confirm.</li><li>The on-chain audit row records <code>source: &#39;telegram_inline&#39;</code>.</li></ul><p><strong>Latency:</strong> the inline tap returns the on-chain settlement notification directly back to the chat.</p><h2 id="tier-2-—-mini-app-otp-200–-5k" tabindex="-1">Tier 2 — Mini-App OTP ($200–$5K) <a class="header-anchor" href="#tier-2-—-mini-app-otp-200–-5k" aria-label="Permalink to &quot;Tier 2 — Mini-App OTP ($200–$5K)&quot;">​</a></h2><p><strong>Flow:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You → /buy 1000 RWA1</span></span>
<span class="line"><span>Bot → classifies as &#39;mini_app_otp&#39;</span></span>
<span class="line"><span>Bot → POSTs intent to backend → backend mints intentId + OTP</span></span>
<span class="line"><span>Backend → delivers OTP via passkey-auth&#39;d webhook (today: registered email)</span></span>
<span class="line"><span>Bot → renders message with Mini-App launch button + OTP:</span></span>
<span class="line"><span>        &quot;OTP: 184329 (valid for 5 minutes)</span></span>
<span class="line"><span>         [📱 Open Mini App]&quot;</span></span>
<span class="line"><span>You → tap &quot;Open Mini App&quot;</span></span>
<span class="line"><span>Telegram → opens https://tg.muhaven.app/?intent=oci_xxx inside Telegram</span></span>
<span class="line"><span>Mini App → fetches intent details (cleartext quote, NAV, share estimate)</span></span>
<span class="line"><span>Mini App → prompts for the 6-digit OTP</span></span>
<span class="line"><span>You → enter OTP</span></span>
<span class="line"><span>Mini App → POSTs /api/v1/agent/openclaw/intent/confirm</span></span>
<span class="line"><span>        body: { intentId, otp, telegramInitData }</span></span>
<span class="line"><span>Backend → verifies Telegram initData HMAC against bot token</span></span>
<span class="line"><span>Backend → resolves user_id from telegram_links (initData branch wins over JWT)</span></span>
<span class="line"><span>Backend → asserts intent.tier === &#39;mini_app_otp&#39;</span></span>
<span class="line"><span>Backend → asserts intent.userId === resolvedUserId (404 if mismatch)</span></span>
<span class="line"><span>Backend → submits the on-chain UserOp</span></span>
<span class="line"><span>Bot ← SSE notification ← Backend</span></span>
<span class="line"><span>Bot → &quot;✅ Settled. Tx: 0x...&quot;</span></span></code></pre></div><p><strong>Security properties:</strong></p><ul><li>The OTP is short-lived (5 minutes), single-use, and bound server-side to <code>(intentId, telegramUserId)</code>.</li><li>Telegram <code>initData</code> is HMAC-verified against the bot token — even a phishing Mini App can&#39;t fake initData.</li><li>The audit row records <code>source: &#39;mini_app&#39;</code>.</li><li>The exact OTP-delivery channel is intentionally flexible: today the OTP is returned in the bot message itself for simplicity.</li></ul><p><strong>Latency:</strong> depends on how fast you retrieve and enter the OTP; once submitted, settlement mirrors the inline tier.</p><h2 id="tier-3-—-passkey-deeplink-5k" tabindex="-1">Tier 3 — Passkey deeplink (&gt;$5K) <a class="header-anchor" href="#tier-3-—-passkey-deeplink-5k" aria-label="Permalink to &quot;Tier 3 — Passkey deeplink (&gt;$5K)&quot;">​</a></h2><p><strong>Flow:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You → /buy 10000 RWA1</span></span>
<span class="line"><span>Bot → classifies as &#39;passkey_deeplink&#39;</span></span>
<span class="line"><span>Bot → POSTs intent to backend → mints intentId</span></span>
<span class="line"><span>Bot → renders message with deeplink:</span></span>
<span class="line"><span>        &quot;For &gt;$5K, confirm with your passkey on the dashboard.</span></span>
<span class="line"><span>         [🔑 Open passkey dashboard]&quot;</span></span>
<span class="line"><span>You → tap the button → default browser opens https://muhaven.app/agent/confirm?intent=oci_xxx</span></span>
<span class="line"><span>Dashboard → loads the ConfirmIntentPage</span></span>
<span class="line"><span>Dashboard → fetches intent details (cleartext quote, NAV, share estimate)</span></span>
<span class="line"><span>Dashboard → renders cleartext preview + &quot;Confirm with passkey&quot; button</span></span>
<span class="line"><span>You → tap Confirm</span></span>
<span class="line"><span>Dashboard → invokes WebAuthn ceremony (passkey assertion)</span></span>
<span class="line"><span>Dashboard → POSTs /api/v1/agent/openclaw/intent/confirm</span></span>
<span class="line"><span>        body: { intentId, passkeyAssertion }</span></span>
<span class="line"><span>Backend → asserts intent.tier === &#39;passkey_deeplink&#39;</span></span>
<span class="line"><span>Backend → asserts source === &#39;dashboard_passkey&#39;</span></span>
<span class="line"><span>Backend → verifies passkeyAssertion (presence check; full WebAuthn verify is the upgrade target)</span></span>
<span class="line"><span>Backend → submits the on-chain UserOp</span></span>
<span class="line"><span>Dashboard → SSE notification → &quot;Settled&quot; + Arbiscan link</span></span>
<span class="line"><span>Bot → also notified via SSE → Telegram message &quot;✅ Settled.&quot;</span></span></code></pre></div><p><strong>Security properties:</strong></p><ul><li>Passkey RP-ID hard-pinned to the dashboard origin (<code>muhaven.app</code>). A Telegram-MITM cannot complete the ceremony.</li><li>The passkey ceremony is rooted in WebAuthn — the strongest auth primitive in the stack.</li><li>The audit row records <code>source: &#39;dashboard_passkey&#39;</code>.</li></ul><div class="warning custom-block"><p class="custom-block-title">Tier 3 passkey assertion</p><p>The current build ships a presence-check <code>passkeyAssertion</code>. The backend rejects empty/missing assertions (401) but accepts any non-empty value. <strong>The dashboard JWT itself is passkey-rooted via the ZeroDev-powered MuHaven wallet registration</strong>, so the demo-path security is acceptable — but a stolen JWT (CSRF, leaked refresh, XSS sibling tab) could complete a &gt;$5K confirm without re-touching a passkey. A full <code>navigator.credentials.get()</code> assertion + server-side <code>@simplewebauthn/server.verifyAuthenticationResponse</code> is the planned hardening; the wire shape is already in place so the upgrade is purely additive.</p></div><h2 id="cross-tier-audit-honesty" tabindex="-1">Cross-tier audit honesty <a class="header-anchor" href="#cross-tier-audit-honesty" aria-label="Permalink to &quot;Cross-tier audit honesty&quot;">​</a></h2><p>Each tier emits a different <code>source</code> in the audit log:</p><table tabindex="0"><thead><tr><th>Tier</th><th>Source</th></tr></thead><tbody><tr><td>Inline</td><td><code>telegram_inline</code></td></tr><tr><td>Mini-App OTP</td><td><code>mini_app</code></td></tr><tr><td>Passkey deeplink</td><td><code>dashboard_passkey</code></td></tr></tbody></table><p>The <code>source</code> is <strong>server-derived</strong> from the auth path — investors and bot workers cannot spoof it. A <code>telegram_inline</code> row guarantees the action settled via the inline tier; a <code>dashboard_passkey</code> row guarantees the WebAuthn ceremony fired.</p><p>This is the <strong>server-derived-source pattern</strong> — the audit log is honest about <em>how</em> an action was confirmed, not just <em>that</em> it was confirmed.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/openclaw/telegram-bot">Telegram bot</a> — link your Telegram, send commands.</li><li><a href="/openclaw/tools">Available tools</a> — the 11-tool subset.</li><li><a href="/policy/audit-log">Audit log</a> — what&#39;s recorded per tier.</li></ul>`,37)])])}const k=s(t,[["render",p]]);export{u as __pageData,k as default};
